BuffConfig = {}
BuffConfig.Config = {}

BuffConfig.initProperties = {
    speedPercent = 1,
    attackSpeedPercent = 1,
    attackPercent = 1,
    attack = 0,
    curExp = 0,
    curLevel = 0,
    defensePercent = 1,
    defense = 0,
    isControl = 0,
}

function BuffConfig:init(config)
    for _, v in pairs(config) do
        local item = {}
        item.Id = tonumber(v.Id)
        item.targetEffect = tostring(v.targetEffect) or ""
        item.duration = tonumber(v.duration) or 0
        item.classId = tonumber(v.classId) or 0
        item.classLevel = tonumber(v.classLevel) or 0
        item.properties = {}
        item.properties["speedPercent"] = tonumber(v.speedPercent) or 0
        item.properties["attackSpeedPercent"] = tonumber(v.attackSpeedPercent) or 0
        item.properties["attackPercent"] = tonumber(v.attackPercent) or 0
        item.properties["attack"] = tonumber(v.attack) or 0
        item.properties["defensePercent"] = tonumber(v.defensePercent) or 0
        item.properties["defense"] = tonumber(v.defense) or 0
        item.properties["isControl"] = tonumber(v.isControl) or 0
        item.properties["curExp"] = 0
        item.properties["curLevel"] = 0
        item.recoveryCurPercent = tonumber(v.recoveryCurPercent) or 0
        item.recoveryMaxPercent = tonumber(v.recoveryMaxPercent) or 0
        item.recovery = tonumber(v.recovery) or 0
        item.recoveryColor = tonumber(v.recoveryColor) or 1
        item.recoveryInterval = tonumber(v.recoveryInterval) or 0
        self.Config[item.Id] = item
    end
end

function BuffConfig:getConfigById(id)
    return self.Config[id]
end

